  useEffect(() =&gt; {
    // Step 2: When proof is ready, embed it
    if (proof &amp;&amp; requestId) {
      provingClient.embedProof(photoUri, proof).then((provenPath) =&gt; {
        console.log(&quot;Proof embedded:&quot;, provenPath);
